// ── CRUD ──
async function savePlayer() {
  const nome = document.getElementById('f-nome').value.trim()
  if (!nome) { showToast('O nome é obrigatório', 'error'); return }
  const btn = document.getElementById('form-save')
  btn.disabled = true
  btn.textContent = 'A guardar...'

  // Handle local file upload
  const fileInput = document.getElementById('f-foto-file')
  let fotoUrl = document.getElementById('f-foto').value.trim() || null
  if (fileInput && fileInput.files && fileInput.files[0]) {
    const file = fileInput.files[0]
    fotoUrl = await new Promise((resolve) => {
      const reader = new FileReader()
      reader.onload = e => resolve(e.target.result)
      reader.readAsDataURL(file)
    })
  }

  const ig = document.getElementById('f-instagram').value.trim().replace(/^@/, '')
  const igLink = ig ? `https://www.instagram.com/${ig}/` : null
  const data = {
    nome,
    posicao: document.getElementById('f-posicao').value || null,
    nivel: document.getElementById('f-nivel-form').value || null,
    clube: document.getElementById('f-clube').value.trim() || null,
    ano: parseInt(document.getElementById('f-ano-form').value) || null,
    representante: document.getElementById('f-representante').value.trim() || null,
    referenciador: document.getElementById('f-referenciador').value.trim() || null,
    telefone: document.getElementById('f-telefone').value.trim() || null,
    instagram: ig || null,
    instagram_link: igLink,
    foto: fotoUrl,
    link: document.getElementById('f-link').value.trim() || null,
    video: document.getElementById('f-video').value.trim() || null,
    notas: document.getElementById('f-notas').value.trim() || null,
  }
  let error
  // Determine correct table - use player's original table if in geral
  let activeTable
  if (state.editingPlayer && state.editingPlayer._sourceTable) {
    activeTable = state.editingPlayer._sourceTable
  } else {
    activeTable = DATABASES.find(d => d.id === state.activeDb)?.table || 'players'
  }
  // Remove null values to avoid column-not-found errors on different tables
  const cleanData = Object.fromEntries(Object.entries(data).filter(([_, v]) => v !== null && v !== undefined && v !== ''))
  let result
  if (state.editingPlayer) {
    result = await supabase.from(activeTable).update(cleanData).eq('id', state.editingPlayer.id)
  } else {
    cleanData.data_insercao = new Date().toISOString().split('T')[0]
    result = await supabase.from(activeTable).insert(cleanData)
  }
  error = result.error
  if (error) {
    showToast('Erro: ' + error.message, 'error')
    btn.disabled = false
    btn.textContent = state.editingPlayer ? 'Guardar' : 'Adicionar jogador'
    return
  }
  const isNew = !state.editingPlayer
  showToast(isNew ? 'Jogador adicionado!' : 'Jogador atualizado!', 'success')
  if (isNew) {
    sendLocalNotification('Novo jogador adicionado!', `${nome} foi adicionado à base de dados.`)
  }
  // Clear ALL cache and force fresh reload
  Object.keys(state.dbCache).forEach(k => { state.dbCache[k] = null })
  closeAll()
  await loadPlayers()
}

async function deletePlayer(player) {
  if (!confirm(`Tens a certeza que queres eliminar "${player.nome}"?`)) return
  const { error } = await supabase.from(player._sourceTable || DATABASES.find(d => d.id === state.activeDb)?.table || 'players').delete().eq('id', player.id)
  if (error) { showToast('Erro ao eliminar.', 'error'); return }
  showToast('Jogador eliminado.', 'success')
  closeAll()
  // Clear cache so fresh data is loaded
  state.dbCache[state.activeDb] = null
  state.dbCache['geral'] = null
  await loadPlayers()
}


// Preload all tabs in background
async function preloadAll() {
  // Load all tables in parallel
  const tables = DATABASES.filter(db => !db.isGeral && db.table)
  const results = await Promise.all(tables.map(db => supabase.from(db.table).select('*')))
  tables.forEach((db, i) => {
    const { data } = results[i]
    if (data) state.dbCache[db.id] = data.map(p => ({ ...p, ano: p.ano != null ? String(p.ano) : '' }))
  })
  // Build geral from cache
  const all = [
    ...(state.dbCache['mercado'] || []).map(p => ({...p, _source: 'Mercado', _sourceTable: 'players_mercado'})),
    ...(state.dbCache['cbf'] || []).map(p => ({...p, _source: 'CBF Seleções', _sourceTable: 'players'})),
    ...(state.dbCache['fpf'] || []).map(p => ({...p, _source: 'FPF Seleções', _sourceTable: 'players_portugal'})),
    ...(state.dbCache['ligas-portugal'] || []).map(p => ({...p, _source: 'Liga Portugal', _sourceTable: 'players_ligas_portugal'})),
    ...(state.dbCache['ligas-brasil'] || []).map(p => ({...p, _source: 'Brasileirão', _sourceTable: 'players_ligas_brasil'})),
  ].sort((a,b) => (a.nome||'').localeCompare(b.nome||''))
  state.dbCache['geral'] = all
}
async function loadPedidos() {
  const { data, error } = await supabase.from('club_requests').select('*').order('clube')
  if (error) { showToast('Erro ao carregar pedidos.', 'error'); return }
  state.pedidos = data || []
  renderPedidos()
}

